// react-router-dom
import {Routes, Route} from 'react-router-dom';

import IndexPage from "./pages/IndexPage/IndexPage";

function App() {
  return (
    <Routes>
      <Route index path="/" element={<IndexPage />} />
      <Route path="/news" element={<Entry />} />
    </Routes>
  );
}

export default App;
